import json,re,collections
rows=[json.loads(l) for l in open('gpt55_board/WhaleCloud-DocChain_0612.jsonl')]
c=collections.Counter()
for r in rows:
    for m in re.finditer(r'.{40}(置信度|证据强度|可信度|Confidence|证据等级).{45}',r['article']):
        c[m.group(0).replace(chr(10),' ')]+=1
for k,v in list(c.items())[:12]: print('|',k)
print()
# table header vocabulary -- reveals the analytic frames
h=collections.Counter()
for r in rows:
    for line in r['article'].split('\n'):
        if line.strip().startswith('|'):
            for cell in line.split('|')[1:-1]:
                cell=cell.strip()
                if 1<len(cell)<12 and not re.match(r'^[-: ]+$',cell): h[cell]+=1
print('TOP TABLE CELLS:', [k for k,v in h.most_common(40)])
"
